# C0684 · CRUD JSON
from flask import Flask, request, jsonify
app = Flask(__name__)
items = {}
seq = 1

@app.get("/items")
def list_items():
    return jsonify(list(items.values()))

@app.post("/items")
def create_item():
    global seq
    data = request.get_json(force=True) or {}
    it = {"id": seq, "name": str(data.get("name",""))}
    items[seq] = it
    seq += 1
    return jsonify(it), 201
